using UnityEngine;

public class LevelDesign : MonoBehaviour
{
    public GameObject[] levelChunks;
    public Transform spawnPoint;
    public Transform endPoint;

    public int playerScore = 0;
    public int enemiesDefeated = 0;
    public bool levelComplete = false;

    void Start()
    {
        Debug.Log("=== Level Design Principles ===");
        Debug.Log("1. Start simple, build complexity");
        Debug.Log("2. Introduce one mechanic at a time");
        Debug.Log("3. Give the player a clear goal");
        Debug.Log("4. Provide feedback for actions");
        Debug.Log("5. Respect the player's time");
    }

    void Update()
    {
        // Simulate level progress
        if (Input.GetKeyDown(KeyCode.Alpha1))
        {
            SpawnChunk(0);
        }
        if (Input.GetKeyDown(KeyCode.Alpha2))
        {
            SpawnChunk(1);
        }
        if (Input.GetKeyDown(KeyCode.Alpha3))
        {
            CompleteLevel();
        }
    }

    void SpawnChunk(int index)
    {
        if (index < levelChunks.Length)
        {
            Instantiate(levelChunks[index], Vector3.zero, Quaternion.identity);
            Debug.Log("Spawned level chunk: " + levelChunks[index].name);
        }
    }

    void CompleteLevel()
    {
        levelComplete = true;
        Debug.Log("🎉 Level Complete!");
        Debug.Log("Score: " + playerScore);
        Debug.Log("Enemies Defeated: " + enemiesDefeated);
    }
}

